<div class="grid-2"><div class="card"><h3>Add Bill Category</h3><form method="post" action="<?= base_url('index.php?route=admin/bill-categories/store') ?>"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><div class="form-group"><label>Name</label><input type="text" name="name" required></div><div class="form-group"><label>Code</label><input type="text" name="code" required></div><button class="btn btn-primary" type="submit">Add Category</button></form></div><div class="card"><h3>Current Categories</h3><div class="table-wrap"><table><thead><tr><th>Name</th><th>Code</th><th>Status</th><th>Action</th></tr></thead><tbody><?php foreach ($categories as $category): ?><tr><td><?= e($category['name']) ?></td><td><?= e($category['code']) ?></td><td><?= e($category['status']) ?></td><td><form method="post" action="<?= base_url('index.php?route=admin/bill-categories/toggle') ?>" class="inline-form"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><input type="hidden" name="id" value="<?= (int)$category['id'] ?>"><button class="btn btn-sm btn-outline">Toggle</button></form></td></tr><?php endforeach; ?></tbody></table></div></div></div>
